INSERT INTO `about_pages` VALUES (1,'about_hero','Navigating the Future of <br>  <span class=\"highlight-blue\"> Logistics </span>','From warehouse to world — we cover it all.',NULL,NULL,'2025-12-22 02:47:06','2025-12-22 03:42:30'),(2,'about_main_heading','Over two decades of   <br> <span class=\"highlight-blue\">transport and logistics expertise. </span>',NULL,NULL,NULL,'2025-12-22 02:47:06','2025-12-22 03:43:28'),(3,'founder_profile','Ananthakrishnan J','CEO and Founder','Visionary logistics leader with 25+ years of global experience driving innovation, efficiency, and sustainability in transport and facility management. Passionate about transformation, teamwork, and future-ready supply chains.',NULL,'2025-12-22 02:47:06','2025-12-23 04:27:16'),(4,'journey_section','JOURNEY','Ananthakrishnan J','Mr. Ananth is a seasoned executive and strategic leader with over 25 years of distinguished experience in transport, logistics, and integrated facility management. Throughout his career, he has consistently delivered transformative results by driving operational excellence, fostering innovation, and championing sustainable growth across complex, large-scale organizations.',NULL,'2025-12-22 02:47:06','2025-12-22 03:40:54'),(5,'executive_leadership','Executive Leadership and Strategic Vision',NULL,'Currently, Mr. Ananth leads Transport & Logistics operations in Saudi Arabia, overseeing a workforce exceeding 2,500 professionals and managing multi-million-dollar budgets. His leadership is grounded in aligning logistics strategies with broader organizational and national objectives, including Saudi Arabia’s Vision 2030. By spearheading initiatives focused on process optimization, automation, and green logistics, he has successfully delivered significant cost efficiencies and enhanced operational resilience, while advancing sustainability goals that set new industry standards.',NULL,'2025-12-22 02:47:06','2025-12-22 03:39:39'),(6,'commitment_section','Commitment to the Industry',NULL,'Ananth Decodes Logistics is a reflection of Mr. Ananth’s passion for demystifying the complexities of logistics and supply chain management. Through this platform, he aims to share insights, best practices, and strategic guidance that empower businesses and professionals to navigate the evolving logistics landscape with confidence and agility.\r\n\r\nHe is deeply committed to fostering a culture of continuous learning and innovation within the logistics community, encouraging collaboration among industry stakeholders to drive collective growth. Mr. Ananth believes that the future of logistics lies in embracing digital transformation, sustainability, and data-driven decision-making, and he strives to be at the forefront of these advancements.\r\n\r\nHis vision extends beyond operational excellence to creating resilient, adaptive supply chains that can withstand global challenges and disruptions. Through thought leadership and active engagement, he seeks to inspire the next generation of logistics professionals and contribute meaningfully to the evolution of the industry worldwide.',NULL,'2025-12-22 02:47:06','2025-12-22 03:39:39'),(7,'expertise_section','Proven Expertise Across Global Enterprises',NULL,'His professional journey spans leadership roles at globally recognized firms such as JLL India, CBRE, Capita India, Omega Healthcare, and Sutherland Global Services. At JLL India, he directed integrated facility management for a 2-million-square-foot campus, leading a multidisciplinary team of over 15,000 personnel. He championed digital transformation and compliance excellence, consistently achieving superior service delivery and operational cost savings.\r\n\r\nIn his role as National Transport Manager at CBRE, Mr. Ananth managed pan-India employee transport for over 15,000 employees across seven major cities, overseeing a substantial annual budget. Through strategic route optimization, vendor negotiations, and the implementation of India’s first fully automated transport procurement system, he delivered double-digit cost reductions and elevated service quality, transparency, and employee satisfaction.',NULL,'2025-12-22 03:39:39','2025-12-22 03:39:39'),(8,'innovation_section','Innovation, Sustainability, and Continuous Improvement',NULL,'Mr. Ananth is deeply committed to leveraging technology and data-driven insights to build agile, efficient, and sustainable supply chains. His leadership philosophy emphasizes the integration of cutting-edge digital tools and green logistics practices to future-proof operations and reduce environmental impact.',NULL,'2025-12-22 03:39:39','2025-12-22 03:44:17'),(9,'academic_credentials','Academic Credentials',NULL,'Pursuing\r\nDoctorate in Business Administration\r\nRushford Business School, Switzerland\r\n\r\nBachelor’s Degree\r\nBusiness Administration\r\nUniversity of Madras, India\r\n\r\nOther Expertise\r\nSix Sigma Master Black Belt \r\n<br>',NULL,'2025-12-22 03:39:39','2025-12-22 04:07:47');
